const metrics = $input.first().json;
const alerts = [];
let healthLevel = 'healthy';

// Eşik değerleri
if (metrics.pending_news > 100) {
  alerts.push('⚠️ Bekleyen haber sayısı çok yüksek: ' + metrics.pending_news);
  healthLevel = 'warning';
}
if (metrics.processing_news > 50) {
  alerts.push('⚠️ İşlenen haber sayısı yüksek: ' + metrics.processing_news);
  healthLevel = 'warning';
}
if (metrics.draft_content > 50) {
  alerts.push('⚠️ Taslak içerik birikti: ' + metrics.draft_content);
  healthLevel = 'warning';
}
if (metrics.failed_publications > 10) {
  alerts.push('🚨 Başarısız yayın sayısı kritik: ' + metrics.failed_publications);
  healthLevel = 'critical';
}
if (metrics.unapplied_learning > 20) {
  alerts.push('⚠️ Uygulanmamış öğrenme birikti: ' + metrics.unapplied_learning);
  healthLevel = 'warning';
}
if (metrics.recent_errors > 5) {
  alerts.push('🚨 Son 1 saatte çok fazla hata: ' + metrics.recent_errors);
  healthLevel = 'critical';
}
if (metrics.review_content > 10) {
  alerts.push('⚠️ İnsan incelemesi bekleyen içerik: ' + metrics.review_content);
  healthLevel = 'warning';
}

return [{
  json: {
    timestamp: new Date().toISOString(),
    metrics: metrics,
    alerts: alerts,
    health_level: healthLevel,
    summary: alerts.length === 0 
      ? 'Sistem sağlıklı çalışıyor' 
      : `${alerts.length} uyarı var`
  }
}];
